public class Film {
private String filmName;
private int filmDuration;
public Film(String filmName, int filmDuration) {
this.filmName = filmName;
this.filmDuration = filmDuration;
}
public String getFilmName() {
return filmName;
}
public void setFilmName(String filmName) {
this.filmName = filmName;
}
public int getFilmDuration() {
return filmDuration;
}
public void setFilmDuration(int filmDuration) {
this.filmDuration = filmDuration;
}
public String getFilmDetails() {
return "Film Name: " + filmName + "\n" +
"Duration: " + filmDuration + " minutes";
}
public static void main(String[] args) {
Film film1 = new Film("Ab", 136); 
System.out.println(film1.getFilmDetails());
film1.setFilmDuration(150); 
film1.setFilmName("Ac"); 
System.out.println("\nUpdated Film Details:\n" + film1.getFilmDetails());
}
}

